14378       Indices.assign(1, OffsetReg0);
14379       for (auto [Pos, I] : enumerate(Mask)) {
14380         if (I == PoisonMaskElem)
14381           continue;
14382         int Idx = I - OffsetReg0;
14383         int RegId =
14384             (Idx / NumElts) * NumParts + (Idx % NumElts) / EltsPerVector;
14385         if (FirstRegId < 0)
