14396                     [&](int S, int I) {
14397                       if (I == PoisonMaskElem)
14398                         return S;
14399                       int RegId = ((I - OffsetReg0) / NumElts) * NumParts +
14400                                   ((I - OffsetReg0) % NumElts) / EltsPerVector;
14401                       if (RegId == FirstRegId)
14402                         return S;
14403                       return std::min(S, I);
14404                     }),
14405                 EltsPerVector);
14406             unsigned Index = OffsetReg1 % NumElts;
14407             Indices.push_back(Index);
14408             SubVecSizes.push_back(std::min(NumElts - Index, EltsPerVector));
14409           }
14410           Idx = I - OffsetReg1;
14411         }
14412         I = (Idx % NumElts) % EltsPerVector +
14413             (RegId == FirstRegId ? 0 : EltsPerVector);
14414       }
