13305 /// Check if we can convert fadd/fsub sequence to FMAD.
13306 /// \returns Cost of the FMAD, if conversion is possible, invalid cost otherwise.
13307 static InstructionCost canConvertToFMA(ArrayRef<Value *> VL,
13308                                        const InstructionsState &S,
13309                                        DominatorTree &DT, const DataLayout &DL,
13310                                        TargetTransformInfo &TTI,
13311                                        const TargetLibraryInfo &TLI) {
13312   assert(all_of(VL,
13313                 [](Value *V) {
13314                   return V->getType()->getScalarType()->isFloatingPointTy();
13315                 }) &&
13316          "Can only convert to FMA for floating point types");
13317   assert(S.isAddSubLikeOp() && "Can only convert to FMA for add/sub");
13318 
13319   auto CheckForContractable = [&](ArrayRef<Value *> VL) {
13320     FastMathFlags FMF;
13321     FMF.set();
13322     for (Value *V : VL) {
13323       auto *I = dyn_cast<Instruction>(V);
13324       if (!I)
13325         continue;
13326       if (S.isCopyableElement(I))
13327         continue;
13328       Instruction *MatchingI = S.getMatchingMainOpOrAltOp(I);
13329       if (S.getMainOp() != MatchingI && S.getAltOp() != MatchingI)
13330         continue;
13331       if (auto *FPCI = dyn_cast<FPMathOperator>(I))
13332         FMF &= FPCI->getFastMathFlags();
13333     }
13334     return FMF.allowContract();
13335   };
13336   if (!CheckForContractable(VL))
13337     return InstructionCost::getInvalid();
13338   // fmul also should be contractable
13339   InstructionsCompatibilityAnalysis Analysis(DT, DL, TTI, TLI);
13340   SmallVector<BoUpSLP::ValueList> Operands = Analysis.buildOperands(S, VL);
13341 
13342   InstructionsState OpS = getSameOpcode(Operands.front(), TLI);
13343   if (!OpS.valid())
13344     return InstructionCost::getInvalid();
13345 
13346   if (OpS.isAltShuffle() || OpS.getOpcode() != Instruction::FMul)
13347     return InstructionCost::getInvalid();
13348   if (!CheckForContractable(Operands.front()))
13349     return InstructionCost::getInvalid();
13350   // Compare the costs.
13351   InstructionCost FMulPlusFAddCost = 0;
13352   InstructionCost FMACost = 0;
13353   constexpr TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
13354   FastMathFlags FMF;
13355   FMF.set();
13356   for (Value *V : VL) {
13357     auto *I = dyn_cast<Instruction>(V);
13358     if (!I)
13359       continue;
13360     if (!S.isCopyableElement(I))
13361       if (auto *FPCI = dyn_cast<FPMathOperator>(I))
13362         FMF &= FPCI->getFastMathFlags();
13363     FMulPlusFAddCost += TTI.getInstructionCost(I, CostKind);
13364   }
13365   unsigned NumOps = 0;
13366   for (auto [V, Op] : zip(VL, Operands.front())) {
13367     if (S.isCopyableElement(V))
13368       continue;
13369     auto *I = dyn_cast<Instruction>(Op);
13370     if (!I || !I->hasOneUse() || OpS.isCopyableElement(I)) {
13371       if (auto *OpI = dyn_cast<Instruction>(V))
13372         FMACost += TTI.getInstructionCost(OpI, CostKind);
13373       if (I)
13374         FMACost += TTI.getInstructionCost(I, CostKind);
13375       continue;
13376     }
13377     ++NumOps;
13378     if (auto *FPCI = dyn_cast<FPMathOperator>(I))
13379       FMF &= FPCI->getFastMathFlags();
13380     FMulPlusFAddCost += TTI.getInstructionCost(I, CostKind);
13381   }
13382   Type *Ty = VL.front()->getType();
13383   IntrinsicCostAttributes ICA(Intrinsic::fmuladd, Ty, {Ty, Ty, Ty}, FMF);
13384   FMACost += NumOps * TTI.getIntrinsicInstrCost(ICA, CostKind);
13385   return FMACost < FMulPlusFAddCost ? FMACost : InstructionCost::getInvalid();
