6689     return nullptr;
6690   int Size = DL.getTypeStoreSize(ElemTy);
6691   auto TryGetStride = [&](const SCEV *Dist,
6692                           const SCEV *Multiplier) -> const SCEV * {
6693     if (const auto *M = dyn_cast<SCEVMulExpr>(Dist)) {
6694       if (M->getOperand(0) == Multiplier)
6695         return M->getOperand(1);
6696       if (M->getOperand(1) == Multiplier)
6697         return M->getOperand(0);
6698       return nullptr;
6699     }
6700     if (Multiplier == Dist)
6701       return SE.getConstant(Dist->getType(), 1);
6702     return SE.getUDivExactExpr(Dist, Multiplier);
6703   };
6704   // Stride_in_elements = Dist / element_size * (num_elems - 1).
6705   const SCEV *Stride = nullptr;
6706   if (Size != 1 || SCEVs.size() > 2) {
6707     const SCEV *Sz = SE.getConstant(Dist->getType(), Size * (SCEVs.size() - 1));
6708     Stride = TryGetStride(Dist, Sz);
6709     if (!Stride)
6710       return nullptr;
6711   }
6712   if (!Stride || isa<SCEVConstant>(Stride))
6713     return nullptr;
6714   // Iterate through all pointers and check if all distances are
6715   // unique multiple of Stride.
6716   using DistOrdPair = std::pair<int64_t, int>;
6717   auto Compare = llvm::less_first();
6718   std::set<DistOrdPair, decltype(Compare)> Offsets(Compare);
6719   int Cnt = 0;
6720   bool IsConsecutive = true;
6721   for (const auto [Idx, PtrSCEV] : enumerate(SCEVs)) {
6722     unsigned Dist = 0;
6723     if (PtrSCEV != PtrSCEVLowest) {
6724       const SCEV *Diff = SE.getMinusSCEV(PtrSCEV, PtrSCEVLowest);
6725       const SCEV *Coeff = TryGetStride(Diff, Stride);
6726       if (!Coeff)
6727         return nullptr;
6728       const auto *SC = dyn_cast<SCEVConstant>(Coeff);
6729       if (!SC || isa<SCEVCouldNotCompute>(SC))
6730         return nullptr;
6731       Coeffs[Idx] = (int64_t)SC->getAPInt().getLimitedValue();
6732       if (!SE.getMinusSCEV(PtrSCEV, SE.getAddExpr(PtrSCEVLowest,
6733                                                   SE.getMulExpr(Stride, SC)))
6734                ->isZero())
6735         return nullptr;
6736       Dist = SC->getAPInt().getZExtValue();
6737     } else {
6738       Coeffs[Idx] = 0;
6739     }
6740     // If the strides are not the same or repeated, we can't vectorize.
6741     if ((Dist / Size) * Size != Dist || (Dist / Size) >= SCEVs.size())
6742       return nullptr;
6743     auto Res = Offsets.emplace(Dist, Cnt);
6744     if (!Res.second)
6745       return nullptr;
6746     // Consecutive order if the inserted element is the last one.
6747     IsConsecutive = IsConsecutive && std::next(Res.first) == Offsets.end();
6748     ++Cnt;
6749   }
6750   if (Offsets.size() != SCEVs.size())
6751     return nullptr;
6752   SortedIndices.clear();
6753   if (!IsConsecutive) {
6754     // Fill SortedIndices array only if it is non-consecutive.
6755     SortedIndices.resize(PointerOps.size());
6756     Cnt = 0;
6757     for (const std::pair<int64_t, int> &Pair : Offsets) {
6758       SortedIndices[Cnt] = Pair.second;
6759       ++Cnt;
6760     }
6761   }
6762   return Stride;
6763 }
