6770 /// Returns the cost of the shuffle instructions with the given \p Kind, vector
6771 /// type \p Tp and optional \p Mask. Adds SLP-specifc cost estimation for insert
6772 /// subvector pattern.
6773 static InstructionCost
6774 getShuffleCost(const TargetTransformInfo &TTI, TTI::ShuffleKind Kind,
6775                VectorType *Tp, ArrayRef<int> Mask = {},
6776                TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput,
6777                int Index = 0, VectorType *SubTp = nullptr,
6778                ArrayRef<const Value *> Args = {}) {
6779   VectorType *DstTy = Tp;
6780   if (!Mask.empty())
6781     DstTy = FixedVectorType::get(Tp->getScalarType(), Mask.size());
6782 
6783   if (Kind != TTI::SK_PermuteTwoSrc)
6784     return TTI.getShuffleCost(Kind, DstTy, Tp, Mask, CostKind, Index, SubTp,
6785                               Args);
6786   int NumSrcElts = Tp->getElementCount().getKnownMinValue();
6787   int NumSubElts;
6788   if (Mask.size() > 2 && ShuffleVectorInst::isInsertSubvectorMask(
6789                              Mask, NumSrcElts, NumSubElts, Index)) {
6790     if (Index + NumSubElts > NumSrcElts &&
6791         Index + NumSrcElts <= static_cast<int>(Mask.size()))
6792       return TTI.getShuffleCost(TTI::SK_InsertSubvector, DstTy, Tp, Mask,
6793                                 TTI::TCK_RecipThroughput, Index, Tp);
6794   }
6795   return TTI.getShuffleCost(Kind, DstTy, Tp, Mask, CostKind, Index, SubTp,
6796                             Args);
6797 }
