6799 /// This is similar to TargetTransformInfo::getScalarizationOverhead, but if
6800 /// ScalarTy is a FixedVectorType, a vector will be inserted or extracted
6801 /// instead of a scalar.
6802 static InstructionCost
6803 getScalarizationOverhead(const TargetTransformInfo &TTI, Type *ScalarTy,
6804                          VectorType *Ty, const APInt &DemandedElts, bool Insert,
6805                          bool Extract, TTI::TargetCostKind CostKind,
6806                          bool ForPoisonSrc = true, ArrayRef<Value *> VL = {}) {
6807   assert(!isa<ScalableVectorType>(Ty) &&
6808          "ScalableVectorType is not supported.");
6809   assert(getNumElements(ScalarTy) * DemandedElts.getBitWidth() ==
6810              getNumElements(Ty) &&
6811          "Incorrect usage.");
6812   if (auto *VecTy = dyn_cast<FixedVectorType>(ScalarTy)) {
6813     assert(SLPReVec && "Only supported by REVEC.");
6814     // If ScalarTy is FixedVectorType, we should use CreateInsertVector instead
6815     // of CreateInsertElement.
6816     unsigned ScalarTyNumElements = VecTy->getNumElements();
6817     InstructionCost Cost = 0;
6818     for (unsigned I : seq(DemandedElts.getBitWidth())) {
6819       if (!DemandedElts[I])
6820         continue;
6821       if (Insert)
6822         Cost += getShuffleCost(TTI, TTI::SK_InsertSubvector, Ty, {}, CostKind,
6823                                I * ScalarTyNumElements, VecTy);
6824       if (Extract)
6825         Cost += getShuffleCost(TTI, TTI::SK_ExtractSubvector, Ty, {}, CostKind,
6826                                I * ScalarTyNumElements, VecTy);
6827     }
6828     return Cost;
6829   }
6830   return TTI.getScalarizationOverhead(Ty, DemandedElts, Insert, Extract,
6831                                       CostKind, ForPoisonSrc, VL);
6832 }
