6853 /// This is similar to TargetTransformInfo::getExtractWithExtendCost, but if Dst
6854 /// is a FixedVectorType, a vector will be extracted instead of a scalar.
6855 static InstructionCost getExtractWithExtendCost(
6856     const TargetTransformInfo &TTI, unsigned Opcode, Type *Dst,
6857     VectorType *VecTy, unsigned Index,
6858     TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput) {
6859   if (auto *ScalarTy = dyn_cast<FixedVectorType>(Dst)) {
6860     assert(SLPReVec && "Only supported by REVEC.");
