6864                           Index * ScalarTy->getNumElements(), SubTp) +
6865            TTI.getCastInstrCost(Opcode, Dst, SubTp, TTI::CastContextHint::None,
6866                                 CostKind);
6867   }
6868   return TTI.getExtractWithExtendCost(Opcode, Dst, VecTy, Index, CostKind);
